$r = Invoke-WebRequest -Uri http://localhost:3000/auth/token -Method POST -ContentType "application/json" -Body "{""client_id"":""gateway-client"",""client_secret"":""supersecret123""}" -UseBasicParsing; $t = ($r.Content | ConvertFrom-Json).access_token; for($i=0;$i -lt 15;$i++){try{$res=(Invoke-WebRequest -Uri http://localhost:3000/api/products -Headers @{Authorization="Bearer $t"} -UseBasicParsing);Write-Host "[$i] $($res.StatusCode)"}catch{Write-Host "[$i] RATE LIMITED"}}
